/**
 * T033: Disambiguation Stage Implementation
 *
 * Resolves conflicts between competing categories by applying pairwise adjustments
 * when confidence gaps are below the threshold. Uses DISAMBIGUATOR attributes to
 * help resolve close classification decisions.
 *
 * Reference: DisambiguationNode.js (pairwise adjustments for competing categories)
 * Config: processingConfig.settings.disambiguation.confidenceGapThreshold
 * Logic: Pairwise adjustments per SCORING_LOGIC.md "Disambiguation Stage"
 */

import { EmailMessage } from '../types/email-message';
import { AttributeContext } from '../types/attribute-context';
import { CategoryConfiguration, AttributeRole } from '../types/category-configuration';
import { ClassificationSession } from '../types/classification-session';
import { ClassificationResult } from '../types/classification-result';
import { DISAMBIGUATION_DEFAULTS } from '../config/constants';
import { validateConfidenceThreshold } from '../utils/validation';
import { getCategoryKey, getSubtypeKey, areSubtypesOfSameCategory } from '../utils/category-utils';

/**
 * Result of disambiguation stage
 */
export interface DisambiguationResult {
  competingCategories: CompetingCategoryPair[];
  adjustmentsApplied: DisambiguationAdjustment[];
  originalScores: Record<string, number>;
  updatedScores: Record<string, number>;
  scoreDeltas: Record<string, number>;
  processingDurationMs: number;
  configurationReferences: {
    disambiguationSettingsPath: string;
    confidenceGapThreshold: number;
  };
  // Preserve previous stage data
  [key: string]: unknown;
}

/**
 * Competing category pair requiring disambiguation
 */
export interface CompetingCategoryPair {
  category1: string;
  category2: string;
  scoreGap: number;
  requiresDisambiguation: boolean;
  subtypeCompetition?: boolean;
}

/**
 * Disambiguation adjustment applied to a category
 */
export interface DisambiguationAdjustment {
  category: string;
  attribute: string;
  role: AttributeRole;
  adjustmentAmount: number;
  adjustmentReason: string;
  confidenceFactor: number;
  decayApplied: boolean;
  decayFactor?: number;
}

/**
 * Disambiguation configuration
 */
interface DisambiguationConfig {
  pairwiseAdjustments: boolean;
  confidenceGapThreshold: number;
  maxAdjustmentsPerEmail?: number;
  adjustmentDecayFactor?: number;
  enableSubtypeDisambiguation?: boolean;
}

/**
 * Execute disambiguation stage (canonical signature)
 *
 * Analyzes candidate scores to identify competing categories and applies
 * targeted adjustments using DISAMBIGUATOR attributes to resolve conflicts.
 *
 * Mutates the result object in place by updating scoreBreakdown with disambiguated scores.
 *
 * @param email - Email message being classified (canonical signature parameter, not used directly)
 * @param session - Classification session batch metadata (canonical signature parameter, not used directly)
 * @param result - Classification result to update (mutated in place)
 * @param config - Category configuration with disambiguation rules
 */
export function executeDisambiguation(
  _email: EmailMessage,
  _session: ClassificationSession,
  result: ClassificationResult,
  config: CategoryConfiguration
): void {
  const startTime = Date.now();

  // Validate configuration
  if (!config.processingConfig?.settings?.disambiguation) {
    throw new Error('Disambiguation configuration not found');
  }

  .optional(),
disambiguation: z
  .object({
    pairwiseAdjustments: z.boolean().default(true),
    confidenceGapThreshold: ThresholdSchema.default(0.1),
    maxAdjustmentsPerCategory: z.number().int().min(1).default(3).optional(),
  })
  .optional(),
multiLabelSelection: z.object({
  maxLabels: z.number().int().min(1).default(3),
  minSecondaryConfidence: ThresholdSchema.default(0.6),
  allowedCombinations: z
    .array(
      z.object({
        categories: z.array(z.string()),
        maxConfidenceSum: z.number().min(0).default(2.0).optional(),
        notes: z.string().optional(),
      })
    )
    .default([]),
  strictCombinationMode: z.boolean().default(false),
}),
aiRouting: z.object({
  highConfidenceThreshold: ThresholdSchema.default(0.8),
  aiRequiredThreshold: ThresholdSchema.default(0.4),
  skipAiConditions: z.array(z.string()).default([]),
  batchSize: z.number().int().min(1).default(10).optional(),
  timeoutMs: z.number().int().min(1000).default(30000).optional(),
}),
performance: z

import { z } from 'zod';

/**
 * Zod schema for CategoryConfiguration validation
 * Validates structure per ${repoRoot}/docs/SCORING_LOGIC.md "Tuning Parameters Summary" section
 */

// Base validation schemas for reusability
const EmailAddressSchema = z.string().email();
const DomainSchema = z.string().regex(/^[a-zA-Z0-9.-]+\.[a-zA-Z]{2,}$/, 'Invalid domain format');
const ConfidenceSchema = z.string().regex(/^(high|medium|low)$/, 'Must be high, medium, or low');
const WeightSchema = z.number().min(0); // No max constraint - weights can be any positive number
const ThresholdSchema = z.number().min(0).max(1);

// Rule pattern validation
export const RulePatternSchema = z.object({
  field: z.enum(['subject', 'body', 'from.address', 'from.name', 'to', 'headers']),
  operation: z.enum(['containsAny', 'startsWith', 'endsWith', 'regexAny', 'exists', 'notContains']),
  values: z.array(z.string()).optional(),
  weight: WeightSchema,
});

// Attribute schemas
const AttributeRoleSchema = z.enum([
  'CORE',
  'PRIMARY_BOOST',
  'SECONDARY_BOOST',
  'DISAMBIGUATOR',
  'FILTER',
  'STRUCTURAL',
  'DERIVED_LINK',
  'NEUTRAL',
]);

const AttributeSchemaDefinition = z.object({
  type: z.enum(['enum', 'boolean', 'string', 'number']),
  values: z.array(z.string()).optional(),
  description: z.string(),
  validation: z
    .object({
      required: z.boolean().default(false),
      min: z.number().optional(),
