     1→/**
     2→ * T033: Disambiguation Stage Implementation
     3→ *
     4→ * Resolves conflicts between competing categories by applying pairwise adjustments
     5→ * when confidence gaps are below the threshold. Uses DISAMBIGUATOR attributes to
     6→ * help resolve close classification decisions.
     7→ *
     8→ * Reference: DisambiguationNode.js (pairwise adjustments for competing categories)
     9→ * Config: processingConfig.settings.disambiguation.confidenceGapThreshold
    10→ * Logic: Pairwise adjustments per SCORING_LOGIC.md "Disambiguation Stage"
    11→ */
    12→
    13→import { EmailMessage } from '../types/email-message';
    14→import { AttributeContext } from '../types/attribute-context';
    15→import { CategoryConfiguration, AttributeRole } from '../types/category-configuration';
    16→import { ClassificationSession } from '../types/classification-session';
    17→import { ClassificationResult } from '../types/classification-result';
    18→import { DISAMBIGUATION_DEFAULTS } from '../config/constants';
    19→import { validateConfidenceThreshold } from '../utils/validation';
    20→import { getCategoryKey, getSubtypeKey, areSubtypesOfSameCategory } from '../utils/category-utils';
    21→
    22→/**
    23→ * Result of disambiguation stage
    24→ */
    25→export interface DisambiguationResult {
    26→  competingCategories: CompetingCategoryPair[];
    27→  adjustmentsApplied: DisambiguationAdjustment[];
    28→  originalScores: Record<string, number>;
    29→  updatedScores: Record<string, number>;
    30→  scoreDeltas: Record<string, number>;
    31→  processingDurationMs: number;
    32→  configurationReferences: {
    33→    disambiguationSettingsPath: string;
    34→    confidenceGapThreshold: number;
    35→  };
    36→  // Preserve previous stage data
    37→  [key: string]: unknown;
    38→}
    39→
    40→/**
    41→ * Competing category pair requiring disambiguation
    42→ */
    43→export interface CompetingCategoryPair {
    44→  category1: string;
    45→  category2: string;
    46→  scoreGap: number;
    47→  requiresDisambiguation: boolean;
    48→  subtypeCompetition?: boolean;
    49→}
    50→
    51→/**
    52→ * Disambiguation adjustment applied to a category
    53→ */
    54→export interface DisambiguationAdjustment {
    55→  category: string;
    56→  attribute: string;
    57→  role: AttributeRole;
    58→  adjustmentAmount: number;
    59→  adjustmentReason: string;
    60→  confidenceFactor: number;
    61→  decayApplied: boolean;
    62→  decayFactor?: number;
    63→}
    64→
    65→/**
    66→ * Disambiguation configuration
    67→ */
    68→interface DisambiguationConfig {
    69→  pairwiseAdjustments: boolean;
    70→  confidenceGapThreshold: number;
    71→  maxAdjustmentsPerEmail?: number;
    72→  adjustmentDecayFactor?: number;
    73→  enableSubtypeDisambiguation?: boolean;
    74→}
    75→
    76→/**
    77→ * Execute disambiguation stage (canonical signature)
    78→ *
    79→ * Analyzes candidate scores to identify competing categories and applies
    80→ * targeted adjustments using DISAMBIGUATOR attributes to resolve conflicts.
    81→ *
    82→ * Mutates the result object in place by updating scoreBreakdown with disambiguated scores.
    83→ *
    84→ * @param email - Email message being classified (canonical signature parameter, not used directly)
    85→ * @param session - Classification session batch metadata (canonical signature parameter, not used directly)
    86→ * @param result - Classification result to update (mutated in place)
    87→ * @param config - Category configuration with disambiguation rules
    88→ */
    89→export function executeDisambiguation(
    90→  _email: EmailMessage,
    91→  _session: ClassificationSession,
    92→  result: ClassificationResult,
    93→  config: CategoryConfiguration
    94→): void {
    95→  const startTime = Date.now();
    96→
    97→  // Validate configuration
    98→  if (!config.processingConfig?.settings?.disambiguation) {
    99→    throw new Error('Disambiguation configuration not found');
   100→  }
   101→
   102→  const disambiguationConfig = config.processingConfig.settings.disambiguation;
   103→  validateDisambiguationConfig(disambiguationConfig);
   104→
   105→  // Extract candidate scores from result.scoreBreakdown
   106→  const candidateScores: Record<string, number> = {};
   107→  for (const [category, scoreData] of Object.entries(result.scoreBreakdown.categoryScores)) {
   108→    candidateScores[category] = scoreData.finalScore || scoreData.baseScore || 0;
   109→  }
   110→
   111→  const updatedScores = { ...candidateScores };
   112→
   113→  // If no scores or insufficient scores, skip disambiguation
   114→  if (Object.keys(candidateScores).length < 2) {
   115→    const duration = Date.now() - startTime;
   116→    result.processingDurationMs += duration;
   117→    result.explainabilityTrace.stageTimings['disambiguation'] = duration;
   118→    result.explainabilityTrace.configurationRefs['disambiguation'] = 'processingConfig.settings.disambiguation';
   119→    return;
   120→  }
   121→
   122→  // Identify competing categories
   123→  const competingCategories = identifyCompetingCategories(candidateScores, disambiguationConfig);
   124→
   125→  // Apply disambiguation adjustments
   126→  const adjustmentsApplied: DisambiguationAdjustment[] = [];
   127→
   128→  if (competingCategories.length > 0) {
   129→    const adjustments = calculateDisambiguationAdjustments(
   130→      competingCategories,
   131→      result.attributeContext,
   132→      config,
   133→      disambiguationConfig
   134→    );
   135→
   136→    // Apply adjustments to scores
   137→    for (const adjustment of adjustments) {
   138→      updatedScores[adjustment.category] = (updatedScores[adjustment.category] || 0) + adjustment.adjustmentAmount;
   139→      adjustmentsApplied.push(adjustment);
   140→    }
   141→  }
   142→
   143→  const duration = Date.now() - startTime;
   144→
   145→  // Mutate result: Update scoreBreakdown with disambiguated scores
   146→  for (const [category, updatedScore] of Object.entries(updatedScores)) {
   147→    if (result.scoreBreakdown.categoryScores[category]) {
   148→      result.scoreBreakdown.categoryScores[category].finalScore = updatedScore;
   149→    }
   150→  }
   151→
   152→  // Add disambiguation applications to scoreBreakdown (convert to ScoreBreakdown format)
   153→  result.scoreBreakdown.disambiguationApplied = competingCategories.map((pair) => ({
   154→    categories: [pair.category1, pair.category2],
   155→    rule: 'disambiguatorAttributes',
   156→    scoreAdjustment: adjustmentsApplied
   157→      .filter((adj) => adj.category === pair.category1 || adj.category === pair.category2)
   158→      .reduce((sum, adj) => sum + adj.adjustmentAmount, 0),
   159→    reason: `Applied DISAMBIGUATOR attributes to resolve ${pair.category1} vs ${pair.category2}`,
   160→    appliedDuringParallelExecution: false,
   161→    dependentOnParallelResults: [],
   162→    adjustmentTimestamp: new Date(),
   163→  }));
   164→
   165→  // Update result processing duration
   166→  result.processingDurationMs += duration;
   167→
   168→  // Add parallel stage result tracking
   169→  result.parallelStageResults.push({
   170→    stageId: `disambiguation_${result.id}`,
   171→    stageName: 'disambiguation',
   172→    executionTimeMs: duration,
   173→    parallelWithStages: [],
   174→    dependentOnStages: ['attributeInfluence'],
   175→    cacheHitsCount: 0,
   176→    errorCount: 0,
   177→  });
   178→
   179→  // Update explainability trace (convert to ExplainabilityTrace.DisambiguationResult format)
   180→  // Group by competing pairs for clearer explainability
   181→  const disambiguationResults = competingCategories.map((pair) => {
   182→    const relevantAdjustments = adjustmentsApplied.filter(
   183→      (adj) => adj.category === pair.category1 || adj.category === pair.category2
   184→    );
   185→    const adjustmentMap: Record<string, number> = {};
   186→    relevantAdjustments.forEach((adj) => {
   187→      adjustmentMap[adj.category] = (adjustmentMap[adj.category] || 0) + adj.adjustmentAmount;
   188→    });
   189→
   190→    // Determine winning category after adjustments
   191→    const score1 = updatedScores[pair.category1] || 0;
   192→    const score2 = updatedScores[pair.category2] || 0;
   193→    const winningCategory = score1 >= score2 ? pair.category1 : pair.category2;
   194→
   195→    return {
   196→      involvedCategories: [pair.category1, pair.category2],
