      const attributeRole = getAttributeRole(attributeName, categoryKey, subtypeKey, config);

      if (attributeRole === 'DISAMBIGUATOR') {
        // Check if we've hit the adjustment limit
        if (
          adjustments.length >=
          (disambiguationConfig.maxAdjustmentsPerEmail || DISAMBIGUATION_DEFAULTS.MAX_ADJUSTMENTS_PER_EMAIL)
        ) {
          break;
        }

        // Calculate adjustment amount
        const categoryAdjustmentCount = categoryAdjustmentCounts[categoryName] || 0;
        const decayFactor = Math.pow(
          disambiguationConfig.adjustmentDecayFactor || DISAMBIGUATION_DEFAULTS.ADJUSTMENT_DECAY_FACTOR,
          categoryAdjustmentCount
        );

        // Base adjustment proportional to confidence
        const baseAdjustment = 0.1 * metadata.confidence; // 10% max adjustment scaled by confidence
        const adjustmentAmount = baseAdjustment * decayFactor;

        adjustments.push({
          category: categoryName,
          attribute: attributeName,
          role: 'DISAMBIGUATOR',
          adjustmentAmount: adjustmentAmount,
          adjustmentReason: 'disambiguatorBonus',
          confidenceFactor: metadata.confidence,
          decayApplied: categoryAdjustmentCount > 0,
          decayFactor: categoryAdjustmentCount > 0 ? decayFactor : undefined,
        });

        categoryAdjustmentCounts[categoryName] = categoryAdjustmentCount + 1;
      }
    }

    // Break if we've hit the global limit
    if (
      adjustments.length >=
      (disambiguationConfig.maxAdjustmentsPerEmail || DISAMBIGUATION_DEFAULTS.MAX_ADJUSTMENTS_PER_EMAIL)
    ) {
      break;
    }
  }

  return adjustments;
}

